+            fallback_policy = mode,
+            statement_kind = "select",
+            decision_reason,
+            group_key_count,
+            window_stage_count,
+            temp_materialization_mode = "connection_aggregate_window_substrate",
+            "execute_statement_dispatch: using pager-backed aggregate/window substrate"
+        );
+    }
